    # Configuration
    ARCHITECTURE = "resnet18"
    NUM_CLASSES = 10
    BATCH_SIZE = 32
    NUM_EPOCHS = 5
    LEARNING_RATE = 1e-3
    DEVICE = torch.device("cuda" if torch.cuda.is_available() else "cpu")

    logger.info(f"Using device: {DEVICE}")

    # Step 1: Load pretrained model
    loader = PretrainedModelLoader(device=DEVICE)

    # Option A: Load from torchvision (recommended, most secure)
    model = loader.load_torchvision_model(
        architecture=ARCHITECTURE,
        num_classes=NUM_CLASSES,
        pretrained_weights=True,
        freeze_backbone=True,
    )

    # Option B: Load from a trusted URL (uncomment to use)
    # model = loader.load_from_url(
    #     architecture="resnet50",
