    #     freeze_backbone=True,
    # )

    # Step 2: Prepare dataset
    logger.info("Preparing dataset...")
    dataset = SyntheticDataset(num_samples=500, num_classes=NUM_CLASSES)
    train_loader, val_loader = create_data_loaders(
        dataset, batch_size=BATCH_SIZE, val_split=0.2
    )

    # Step 3: Fine-tune
    logger.info("Starting fine-tuning...")
    trainer = TransferLearningTrainer(
        model=model,
        device=DEVICE,
        learning_rate=LEARNING_RATE,
    )

    save_dir = os.path.join(tempfile.gettempdir(), "transfer_learning_checkpoints")
    save_path = os.path.join(save_dir, "best_model.pth")

    history = trainer.fit(
        train_loader=train_loader,
        val_loader=val_loader,
        num_epochs=NUM_EPOCHS,
        save_path=save_path,
        early_stopping_patience=3,
    )

    # Step 4: Final evaluation
    final_loss, final_acc = trainer.evaluate(val_loader)
    logger.info(f"Final Validation - Loss: {final_loss:.4f}, Accuracy: {final_acc:.4f}")

    # Step 5: Optionally unfreeze and fine-tune entire model
    logger.info("Unfreezing backbone for full fine-tuning...")
    for param in model.parameters():
        param.requires_grad = True

    trainer_full = TransferLearningTrainer(
        model=model,
        device=DEVICE,
        learning_rate=LEARNING_RATE * 0.1,  # Lower LR for full fine-tuning
    )

    save_path_full = os.path.join(save_dir, "best_model_full.pth")
    history_full = trainer_full.fit(
        train_loader=train_loader,
        val_loader=val_loader,
        num_epochs=3,
        save_path=save_path_full,
        early_stopping_patience=3,
    )

    final_loss, final_acc = trainer_full.evaluate(val_loader)
    logger.info(
        f"Full Fine-tune Validation - Loss: {final_loss:.4f}, Accuracy: {final_acc:.4f}"
    )

    logger.info("Transfer learning pipeline completed successfully.")


